from dataclasses import dataclass
from datetime import datetime, timedelta

@dataclass
class RetrainingTrigger:
    reason: str
    urgency: str  # 'immediate' | 'scheduled' | 'opportunistic'
    data_snapshot_id: str

def should_retrain(metrics: dict) -> RetrainingTrigger | None:
    """Check retraining conditions; returns trigger if any condition is met."""

    # Sustained quality degradation
    if metrics["neg_rate_7d"] > 0.08:
        return RetrainingTrigger(
            reason="negative_rate_high",
            urgency="immediate",
            data_snapshot_id=create_snapshot(),
        )

    # Eval score regression
    if metrics["eval_score_delta"] < -0.03:
        return RetrainingTrigger(
            reason="eval_regression",
            urgency="immediate",
            data_snapshot_id=create_snapshot(),
        )

    # New feedback cases accumulated (opportunistic improvement)
    if metrics["new_labelled_cases"] >= 500:
        return RetrainingTrigger(
            reason="feedback_batch_ready",
            urgency="scheduled",
            data_snapshot_id=create_snapshot(),
        )

    # Monthly scheduled run
    if metrics["days_since_last_train"] >= 30:
        return RetrainingTrigger(
            reason="scheduled_monthly",
            urgency="opportunistic",
            data_snapshot_id=create_snapshot(),
        )

    return None
